import { rngAesCtrDrbg256 } from '@noble/ciphers/aes.js';
import { reverseBits } from '@noble/curves/abstract/fft.js';
import { bytesToHex, concatBytes, hexToBytes } from '@noble/hashes/utils.js';
import { describe, should } from '@paulmillr/jsbt/test.js';
import { deepStrictEqual, throws } from 'node:assert';
import { readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import * as falcon from '../src/falcon.ts';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const falconRound3FprH = readFileSync(join(__dirname, 'vectors/falcon/round3/fpr.h'), 'utf8');
const falconRound3FprC = readFileSync(join(__dirname, 'vectors/falcon/round3/fpr.c'), 'utf8');
const { Float } = falcon.__tests;
const falconTest = new Map([
  [falcon.falcon512, falcon.__tests.falcon512],
  [falcon.falcon512padded, falcon.__tests.falcon512padded],
  [falcon.falcon1024, falcon.__tests.falcon1024],
  [falcon.falcon1024padded, falcon.__tests.falcon1024padded],
]);
const coders = (detached) => falconTest.get(detached);
// Archived Falcon tests expect a closure API, while current noble-ciphers exposes an object.
const aes256_ctr_drbg = (seed, personalization) => {
  const drbg = rngAesCtrDrbg256(seed, personalization);
  return (len, entropy) => drbg.randomBytes(len, entropy);
};
function parseKAT(path) {
  const lines = readFileSync(join(__dirname, path), 'utf8').trim().split('\n');
  const res = {};
  let test = null;
  let group = 'default';
  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed === '') {
      if (test) {
        if (!res[group]) res[group] = [];
        res[group].push(test);
        test = null;
      }
      continue;
    }
    if (trimmed.startsWith('#')) {
      group = trimmed.slice(1).trim() || 'default';
      if (!res[group]) res[group] = [];
      continue;
    }
    const [k, v] = trimmed.split(/\s*=\s*/);
    if (!test) test = {};
    test[k] = v;
  }
  if (test) {
    if (!res[group]) res[group] = [];
    res[group].push(test);
  }
  return res;
}

const match = (src, re) => {
  const m = src.match(re);
  if (!m) throw new Error(`missing pattern: ${re}`);
  return m[1];
};
const round3Fpr = {
  one(name) {
    return BigInt(
      match(falconRound3FprH, new RegExp(`(?:static\\s+)?const fpr ${name} = (\\d+)(?:U)?;`))
    );
  },
  list(name, src = falconRound3FprH) {
    return [
      ...match(
        src,
        new RegExp(`(?:static\\s+)?const fpr ${name}\\[] = \\{(.*?)\\};`, 's')
      ).matchAll(/(\d+)(?:U)?/g),
    ].map((m) => BigInt(m[1]));
  },
};

function floatBits(x) {
  const view = new DataView(new ArrayBuffer(8));
  view.setFloat64(0, x, false);
  return view.getBigUint64(0, false);
}
function floatToOrderedInt(x) {
  const bits = floatBits(x);
  return bits >> 63n === 0n ? bits : ~bits + 1n; // signed ordering
}
const absBigInt = (x) => (x < 0n ? -x : x);
const ulpDiff = (a, b) => absBigInt(floatToOrderedInt(a) - floatToOrderedInt(b));

function epsDiff(a, b) {
  const base = Math.max(Math.abs(a), Math.abs(b), 1);
  return Math.abs(a - b) / (Number.EPSILON * base);
}

function bytesDiff(a, b) {
  const bufA = new DataView(new ArrayBuffer(8));
  const bufB = new DataView(new ArrayBuffer(8));
  bufA.setFloat64(0, a, false);
  bufB.setFloat64(0, b, false);
  for (let i = 0; i < 8; i++) {
    if (bufA.getUint8(i) !== bufB.getUint8(i)) return 8 - i; // bytes that must be patched from i to end
  }
  return 0;
}

// TODO: maybe use? Can save space
const floatPatch = {
  create(actual, required, bytes = 2) {
    if (actual.length !== required.length) throw new Error('Mismatched lengths');
    const patch = new Uint8Array(actual.length * bytes);
    const view = new DataView(new ArrayBuffer(8));
    for (let i = 0; i < actual.length; i++) {
      view.setFloat64(0, required[i], false);
      for (let j = 0; j < bytes; j++) patch[i * bytes + j] = view.getUint8(8 - bytes + j);
    }
    return patch;
  },
  apply(original, patch, bytes = 2) {
    if (patch.length !== original.length * bytes) throw new Error('Invalid patch length');
    const res = new Float64Array(original.length);
    const view = new DataView(new ArrayBuffer(8));
    for (let i = 0; i < original.length; i++) {
      view.setFloat64(0, original[i], false);
      for (let j = 0; j < bytes; j++) view.setUint8(8 - bytes + j, patch[i * bytes + j]);
      res[i] = view.getFloat64(0, false);
    }
    return res;
  },
};

describe('Falcon', () => {
  describe('Roots', () => {
    should('Exact', () => {
      deepStrictEqual(
        Array.from(falcon.__tests.COMPLEX_ROOTS, floatBits),
        round3Fpr.list('fpr_gm_tab', falconRound3FprC)
      );
    });
    should('Generated', () => {
      // COMPLEX ROOT GENERATION FOR FALCON
      // This basically tests that roots are somewhat close to what they should be mathematically
      const GM = new Float64Array(2048);
      GM[0] = 0.0;
      GM[1] = 0.0;
      GM[2] = -0.0;
      GM[3] = 1.0;
      // This is actual logic to generate these roots, but transcendental functions (sin/cos) is pretty broken in js:
      // - they different between env (node/bun)
      //   - unexpectedly, there is no difference between arm and x86
      // - depends on actual implementation
      // In theory it should be ok, but there is tests in KAT that fail if roots are not exact,
      // since even very small difference will be amplified if there is a lot of operations.
      for (let k = 2; k < 1024; k++) {
        const j = reverseBits(k, 10);
        const angle = (j * Math.PI) / 1024.0;
        GM[2 * k + 0] = Math.cos(angle); // real
        GM[2 * k + 1] = Math.sin(angle); // imaginary
      }
      const max = { eps: 0, ulp: 0, bytes: 0 };
      for (let i = 0; i < GM.length; i++) {
        const a = falcon.__tests.COMPLEX_ROOTS[i];
        const b = GM[i];
        const eps = epsDiff(a, b);
        const ulp = ulpDiff(a, b);
        const bytes = bytesDiff(a, b);
        if (eps > 1.5) throw new Error(`eps eql a=${a} b=${b} diff=${eps}`);
        if (ulp > 373) throw new Error(`ulp eql a=${a} b=${b} diff=${ulp}`);
        if (bytes > 2) throw new Error(`bytes eql a=${a} b=${b} diff=${bytes}`);
        if (max.eps < eps) max.eps = eps;
        if (max.ulp < ulp) max.ulp = ulp;
        if (max.bytes < bytes) max.bytes = bytes;
      }
      // console.log('Max root diff', max);
      const patchBytes = 2;
      const patch = floatPatch.create(GM, falcon.__tests.COMPLEX_ROOTS, patchBytes);
      deepStrictEqual(floatPatch.apply(GM, patch, patchBytes), falcon.__tests.COMPLEX_ROOTS);
      // console.log('Patch hex length', patch.length * 2);
    });
  });
  should('Exact constants', () => {
    deepStrictEqual(falcon.__tests.INV_SIGMA.map(floatBits), round3Fpr.list('fpr_inv_sigma'));
    deepStrictEqual(falcon.__tests.SIGMA_MIN.map(floatBits), round3Fpr.list('fpr_sigma_min'));
    deepStrictEqual(floatBits(falcon.__tests.BNORM_MAX), round3Fpr.one('fpr_bnorm_max'));
  });
  should('FFT', () => {
    // Strict equality check for fft
    const iS = ['ce56c65b260702a9', 'ce64798dbae700ed', 'ce619c7041fc36c7', 'ce41d6c3598de14f'];
    const i = iS.map(Float.decode);
    const oS = ['ce66b63806f3268d', 'cde0231f13dc1c00', 'ce719f0975ec43b5', '4dc4c99f80677000'];
    const o = oS.map(Float.decode);
    deepStrictEqual(i.map(Float.encode), iS);
    deepStrictEqual(o.map(Float.encode), oS);
    const x = new Float64Array(i);
    return;
    const floatPoly = falcon.__tests.getFloatPoly(2);
    floatPoly.FFT(x);
    deepStrictEqual(x, new Float64Array(o));
  });

  const falcons = [
    ['vectors/falcon/round3/falcon512-KAT.rsp', falcon.falcon512],
    ['vectors/falcon/round3/falcon1024-KAT.rsp', falcon.falcon1024],
    // pqclean
    ['vectors/falcon/pqclean/nistkat_out_falcon-512_clean', falcon.falcon512],
    ['vectors/falcon/pqclean/nistkat_out_falcon-1024_clean', falcon.falcon1024],
    ['vectors/falcon/pqclean/nistkat_out_falcon-padded-512_clean', falcon.falcon512padded],
    ['vectors/falcon/pqclean/nistkat_out_falcon-padded-1024_clean', falcon.falcon1024padded],
  ];
  for (const [file, falcon, skip] of falcons) {
    should(file, () => {
      let firstSig, firstPk;
      for (const [group, items] of Object.entries(parseKAT('./' + file))) {
        for (const t of items) {
          if (skip && skip.includes(t.count)) continue;
          //if (!skip || !skip.includes(t.count)) continue;
          // console.log('---- TEST', file, t);
          const sk = hexToBytes(t.sk);
          deepStrictEqual(bytesToHex(falcon.getPublicKey(sk)), t.pk.toLowerCase());
          const rng = aes256_ctr_drbg(hexToBytes(t.seed));
          const realSeed = rng(48);
          // console.log('SEED', JSON.stringify(Array.from(hexToBytes(t.seed))));
          // console.log('MSG', JSON.stringify(Array.from(hexToBytes(t.msg))));
          const keys = falcon.keygen(realSeed);
          deepStrictEqual(bytesToHex(keys.secretKey), t.sk.toLowerCase());
          deepStrictEqual(bytesToHex(keys.publicKey), t.pk.toLowerCase());
          const msg = hexToBytes(t.msg);
          deepStrictEqual(
            bytesToHex(falcon.attached.seal(msg, keys.secretKey, { random: rng })),
            t.sm.toLowerCase()
          );
          deepStrictEqual(
            bytesToHex(falcon.attached.open(hexToBytes(t.sm), keys.publicKey)),
            t.msg.toLowerCase()
          );
          if (!firstSig) {
            firstSig = hexToBytes(t.sm);
            firstPk = hexToBytes(t.pk);
          } else {
            throws(() => falcon.attached.open(firstSig, keys.publicKey));
          }
        }
      }
    });
  }
  should('falcon1024/detached', () => {
    // Note, there is no KAT's for detached signatures! So we do our own.
    const pk = hexToBytes(
      ''
    );
    const sk = hexToBytes(
      ''
    );
    const msg = hexToBytes(
      ''
    );
    const sm =
      '';
    const sig =
      '';
    const seed = hexToBytes(
      '061550234D158C5EC95595FE04EF7A25767F2E24CC2BC479D09D86DC9ABCFDE7056A8C266F9EF97ED08541DBD2E1FFA1'
    );
    const rng = aes256_ctr_drbg(seed);
    const realSeed = rng(48);
    deepStrictEqual(
      bytesToHex(falcon.falcon1024.attached.seal(msg, sk, { random: rng })),
      sm.toLowerCase()
    );
    deepStrictEqual(
      bytesToHex(falcon.falcon1024.sign(msg, sk, { random: rng })),
      sig.toLowerCase()
    );
    // verify
    deepStrictEqual(
      bytesToHex(falcon.falcon1024.attached.open(hexToBytes(sm), pk)),
      bytesToHex(msg)
    );
    deepStrictEqual(falcon.falcon1024.verify(hexToBytes(sig), msg, pk), true);
  });
  should('detached/validation', () => {
    const msg = hexToBytes('68656c6c6f00');
    const rnd = (len) => new Uint8Array(len).fill(7);
    // Verified against PQClean: unpadded rejects appended bytes,
    // while padded accepts only an all-zero tail.
    const cases = [
      [falcon.falcon512, falcon.falcon512padded, new Uint8Array(48).fill(1)],
      [falcon.falcon1024, falcon.falcon1024padded, new Uint8Array(48).fill(2)],
    ];
    for (const [detached, padded, seed] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const sig = detached.sign(msg, secretKey, { random: rnd });
      deepStrictEqual(detached.verify(sig, msg, publicKey), true);
      deepStrictEqual(
        detached.verify(concatBytes(sig, new Uint8Array([0x00])), msg, publicKey),
        false
      );
      deepStrictEqual(
        detached.verify(concatBytes(sig, new Uint8Array([0x01])), msg, publicKey),
        false
      );
      deepStrictEqual(
        detached.verify(padded.sign(msg, secretKey, { random: rnd }), msg, publicKey),
        false
      );
    }
  });
  should('attached/validation', () => {
    const msg = hexToBytes('68656c6c6f00');
    const rnd = (len) => new Uint8Array(len).fill(7);
    // Unpadded attached signatures reject appended bytes even if the outer length prefix is
    // adjusted, and padded attached signatures accept only all-zero compressed-signature padding.
    const cases = [
      [falcon.falcon512, falcon.falcon512padded, new Uint8Array(48).fill(1)],
      [falcon.falcon1024, falcon.falcon1024padded, new Uint8Array(48).fill(2)],
    ];
    for (const [detached, padded, seed] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const seal = detached.attached.seal(msg, secretKey, { random: rnd });
      deepStrictEqual(detached.attached.open(seal, publicKey), msg);
      for (const extra of [0x00, 0x01]) {
        const len = (seal[0] << 8) | seal[1];
        const bad = new Uint8Array(seal.length + 1);
        bad.set(seal);
        bad[seal.length] = extra;
        bad[0] = ((len + 1) >> 8) & 0xff;
        bad[1] = (len + 1) & 0xff;
        throws(() => detached.attached.open(bad, publicKey));
      }
      const sig = detached.sign(msg, secretKey, { random: rnd });
      const pseal = padded.attached.seal(msg, secretKey, { random: rnd });
      deepStrictEqual(padded.attached.open(pseal, publicKey), msg);
      const pbad = new Uint8Array(pseal);
      pbad[sig.length] = 1;
      throws(() => padded.attached.open(pbad, publicKey));
    }
  });
  should('padded/detached-lengths', () => {
    const msg = Uint8Array.from([1, 2, 3, 4]);
    const random = (len = 0) => new Uint8Array(len).fill(7);
    const { secretKey: sk512 } = falcon.falcon512padded.keygen(new Uint8Array(48).fill(1));
    const { secretKey: sk1024 } = falcon.falcon1024padded.keygen(new Uint8Array(48).fill(2));
    deepStrictEqual(
      {
        lengths: {
          falcon512padded: falcon.falcon512padded.lengths.signature,
          falcon1024padded: falcon.falcon1024padded.lengths.signature,
        },
        sign: {
          falcon512padded: falcon.falcon512padded.sign(msg, sk512, { random }).length,
          falcon1024padded: falcon.falcon1024padded.sign(msg, sk1024, { random }).length,
        },
      },
      {
        lengths: { falcon512padded: 666, falcon1024padded: 1280 },
        sign: { falcon512padded: 666, falcon1024padded: 1280 },
      }
    );
  });
  should('detached/maxS2Len', () => {
    // These payload-only budgets must stay aligned with the vendored PQClean detached limits:
    // total detached bytes minus the detached header byte and 40-byte nonce.
    deepStrictEqual(
      {
        falcon512: falcon.__tests.falcon512.maxS2Len,
        falcon1024: falcon.__tests.falcon1024.maxS2Len,
      },
      {
        falcon512: 711,
        falcon1024: 1421,
      }
    );
  });
  should('padded/validation', () => {
    const msg = hexToBytes('68656c6c6f00');
    const rnd = (len) => new Uint8Array(len).fill(7);
    // Verified against PQClean: padded detached signatures accept
    // only an all-zero tail at the fixed padded length.
    const cases = [
      [falcon.falcon512, falcon.falcon512padded, new Uint8Array(48).fill(1)],
      [falcon.falcon1024, falcon.falcon1024padded, new Uint8Array(48).fill(2)],
    ];
    for (const [detached, padded, seed] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const sig = detached.sign(msg, secretKey, { random: rnd });
      const psig = padded.sign(msg, secretKey, { random: rnd });
      const pbad = new Uint8Array(psig);
      pbad[sig.length] = 1;
      deepStrictEqual(padded.verify(psig, msg, publicKey), true);
      deepStrictEqual(padded.verify(pbad, msg, publicKey), false);
      const seal = padded.attached.seal(msg, secretKey, { random: rnd });
      const sbad = new Uint8Array(seal);
      sbad[sig.length] = 1;
      throws(() => padded.attached.open(sbad, publicKey));
    }
  });
  should('publicKey/validation', () => {
    const msg = hexToBytes('68656c6c6f00');
    const rnd = (len) => new Uint8Array(len).fill(7);
    // Verified against PQClean: modq_decode rejects truncated bodies
    // and coefficients >= 12289, and callers must require exact body length.
    const setFirstCoeff = (pk, w) => {
      const bad = new Uint8Array(pk);
      bad[1] = w >>> 6;
      bad[2] = ((w & 0x3f) << 2) | (bad[2] & 0x03);
      return bad;
    };
    const cases = [
      [falcon.falcon512, new Uint8Array(48).fill(1)],
      [falcon.falcon1024, new Uint8Array(48).fill(2)],
    ];
    for (const [detached, seed] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const sig = detached.sign(msg, secretKey, { random: rnd });
      const { publicKeyCoder } = coders(detached);
      const shortPk = publicKey.subarray(0, publicKey.length - 1);
      const longPk = concatBytes(publicKey, new Uint8Array([1]));
      const badPk = setFirstCoeff(publicKey, 12289);
      throws(() => publicKeyCoder.decode(shortPk));
      throws(() => publicKeyCoder.decode(badPk));
      deepStrictEqual(detached.verify(sig, msg, longPk), false);
      deepStrictEqual(detached.verify(sig, msg, shortPk), false);
      deepStrictEqual(detached.verify(sig, msg, badPk), false);
    }
  });
  should('privateKey/validation', () => {
    const cases = [
      [falcon.falcon512, new Uint8Array(48).fill(1), 0x82],
      [falcon.falcon1024, new Uint8Array(48).fill(2), 0x80],
    ];
    for (const [detached, seed, head] of cases) {
      const { secretKey } = detached.keygen(seed);
      const { privateKeyCoder } = coders(detached);
      const bad = new Uint8Array(secretKey);
      bad[1] = head | (bad[1] & (head === 0x82 ? 0x03 : 0x07));
      throws(() => privateKeyCoder.decode(bad));
      throws(() => detached.getPublicKey(bad));
    }
  });
  should('keyCoder/encode/validation', () => {
    // Verified against PQClean: modq_encode rejects coefficients >= 12289,
    // and trim_i8_encode rejects the forbidden minimum.
    const cases = [
      [falcon.falcon512, new Uint8Array(48).fill(1), -32],
      [falcon.falcon1024, new Uint8Array(48).fill(2), -16],
    ];
    for (const [detached, seed, min] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const { publicKeyCoder, privateKeyCoder } = coders(detached);
      const pub = publicKeyCoder.decode(publicKey);
      const [f, g, F] = privateKeyCoder.decode(secretKey);
      const shortPub = pub.subarray(0, pub.length - 1);
      const longPub = new Uint16Array(pub.length + 1);
      longPub.set(pub);
      longPub[pub.length] = 1;
      const badPub = new Uint16Array(pub);
      badPub[0] = 12289;
      const shortF = f.subarray(0, f.length - 1);
      const longF = new Int8Array(f.length + 1);
      longF.set(f);
      longF[f.length] = 1;
      const badF = new Int8Array(f);
      badF[0] = min;
      throws(() => publicKeyCoder.encode(shortPub));
      throws(() => publicKeyCoder.encode(longPub));
      throws(() => publicKeyCoder.encode(badPub));
      throws(() => privateKeyCoder.encode([shortF, g, F]));
      throws(() => privateKeyCoder.encode([longF, g, F]));
      throws(() => privateKeyCoder.encode([badF, g, F]));
    }
  });
  should('keygen/validation', () => {
    // Round 3 KATs use 48-byte seeds, and PQClean keypair seeds SHAKE from `unsigned char seed[48]`.
    const cases = [
      falcon.falcon512,
      falcon.falcon1024,
      falcon.falcon512padded,
      falcon.falcon1024padded,
    ];
    for (const detached of cases) {
      detached.keygen(new Uint8Array(48).fill(7));
      throws(() => detached.keygen(new Uint8Array(0)));
      throws(() => detached.keygen(new Uint8Array(1)));
      throws(() => detached.keygen(new Uint8Array(47)));
      throws(() => detached.keygen(new Uint8Array(49)));
    }
  });
  should('sign/validation', () => {
    // Round 3 Sign samples a 40-byte nonce, and PQClean also uses fixed nonce/seed buffers.
    const badNonceLens = [0, 1, 39, 41, 80];
    const badSeedLens = [0, 1, 47, 49, 200];
    const badMsgs = [undefined, 1, 'x', {}, []];
    const cases = [
      [falcon.falcon512, new Uint8Array(48).fill(1)],
      [falcon.falcon1024, new Uint8Array(48).fill(2)],
    ];
    for (const [detached, seed] of cases) {
      const { secretKey } = detached.keygen(seed);
      for (const bad of badMsgs) {
        let calls = 0;
        const rnd = (len) => {
          calls++;
          return new Uint8Array(len).fill(calls);
        };
        throws(() => detached.sign(bad, secretKey, { random: rnd }));
        deepStrictEqual(calls, 0);
        throws(() => detached.attached.seal(bad, secretKey, { random: rnd }));
        deepStrictEqual(calls, 0);
      }
      for (const badLen of badNonceLens) {
        let calls = 0;
        const rnd = (len) => {
          calls++;
          return new Uint8Array(calls === 1 ? badLen : len).fill(calls);
        };
        throws(() => detached.sign(new Uint8Array([1, 2, 3]), secretKey, { random: rnd }));
        calls = 0;
        throws(() => detached.attached.seal(new Uint8Array([1, 2, 3]), secretKey, { random: rnd }));
      }
      for (const badLen of badSeedLens) {
        let calls = 0;
        const rnd = (len) => {
          calls++;
          return new Uint8Array(calls === 1 ? len : badLen).fill(calls);
        };
        throws(() => detached.sign(new Uint8Array([1, 2, 3]), secretKey, { random: rnd }));
        calls = 0;
        throws(() => detached.attached.seal(new Uint8Array([1, 2, 3]), secretKey, { random: rnd }));
      }
    }
  });
  should('verify/validation', () => {
    // Keep top-level misuse handling aligned with the other noble signers: wrong JS types should throw,
    // while malformed byte encodings still return false.
    const bads = [undefined, 1, 'x', {}, []];
    const cases = [
      [falcon.falcon512, new Uint8Array(48).fill(1)],
      [falcon.falcon1024, new Uint8Array(48).fill(2)],
    ];
    for (const [detached, seed] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const msg = new Uint8Array([1, 2, 3]);
      const sig = detached.sign(msg, secretKey);
      for (const bad of bads) {
        throws(() => detached.verify(bad, msg, publicKey));
        throws(() => detached.verify(sig, bad, publicKey));
        throws(() => detached.verify(sig, msg, bad));
      }
    }
  });
  should('secret/cleanup', () => {
    const msg = new Uint8Array([1, 2, 3]);
    const zero = (parts) => {
      for (const p of parts) deepStrictEqual(p, new Int8Array(p.length));
    };
    const cases = [
      [falcon.falcon512, new Uint8Array(48).fill(1)],
      [falcon.falcon1024, new Uint8Array(48).fill(2)],
    ];
    for (const [detached, seed] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const { privateKeyCoder } = coders(detached);
      const origDecode = privateKeyCoder.decode.bind(privateKeyCoder);
      try {
        let decoded = origDecode(secretKey);
        privateKeyCoder.decode = () => decoded;
        deepStrictEqual(detached.getPublicKey(secretKey), publicKey);
        zero(decoded);

        decoded = origDecode(secretKey);
        privateKeyCoder.decode = () => decoded;
        const sig = detached.sign(msg, secretKey, { random: (len) => new Uint8Array(len).fill(7) });
        deepStrictEqual(detached.verify(sig, msg, publicKey), true);
        zero(decoded);

        decoded = origDecode(secretKey);
        privateKeyCoder.decode = () => decoded;
        decoded[0].fill(0);
        decoded[1].fill(0);
        decoded[1][0] = 1;
        decoded[2].fill(0);
        throws(() =>
          detached.sign(msg, secretKey, { random: (len) => new Uint8Array(len).fill(7) })
        );
        zero(decoded);
      } finally {
        privateKeyCoder.decode = origDecode;
      }
    }
  });
  should('api/shape', () => {
    const cases = [
      [falcon.falcon512, new Uint8Array(48).fill(1), false],
      [falcon.falcon512padded, new Uint8Array(48).fill(2), true],
      [falcon.falcon1024, new Uint8Array(48).fill(3), false],
      [falcon.falcon1024padded, new Uint8Array(48).fill(4), true],
    ];
    for (const [detached, seed, fixed] of cases) {
      const { publicKey, secretKey } = detached.keygen(seed);
      const sig = detached.sign(new Uint8Array([1, 2, 3]), secretKey);
      deepStrictEqual(detached.info.type, 'falcon');
      deepStrictEqual(detached.lengths.seed, 48);
      deepStrictEqual(detached.lengths.publicKey, publicKey.length);
      deepStrictEqual(detached.lengths.secretKey, secretKey.length);
      deepStrictEqual(detached.lengths.signRand, 48);
      deepStrictEqual(detached.lengths.signature, fixed ? sig.length : undefined);
      deepStrictEqual(detached.attached.info.type, 'falcon');
      deepStrictEqual(detached.attached.lengths.seed, 48);
      deepStrictEqual(detached.attached.lengths.publicKey, publicKey.length);
      deepStrictEqual(detached.attached.lengths.secretKey, secretKey.length);
      deepStrictEqual(detached.attached.lengths.signRand, 48);
      deepStrictEqual(detached.attached.getPublicKey(secretKey), publicKey);
      deepStrictEqual(detached.verify(sig, new Uint8Array([1, 2, 3]), publicKey, {}), true);
      deepStrictEqual(
        detached.verify(
          detached.sign(new Uint8Array([1, 2, 3]), secretKey, { extraEntropy: false }),
          new Uint8Array([1, 2, 3]),
          publicKey
        ),
        true
      );
      throws(() =>
        detached.sign(new Uint8Array([1, 2, 3]), secretKey, { context: new Uint8Array([1]) })
      );
      throws(() =>
        detached.verify(sig, new Uint8Array([1, 2, 3]), publicKey, { context: new Uint8Array([1]) })
      );
    }
  });
  should('secretKey/validation', () => {
    const msg = new Uint8Array([1, 2, 3]);
    const cases = [falcon.falcon512, falcon.falcon1024];
    for (const detached of cases) {
      const n = detached.lengths.publicKey === 897 ? 512 : 1024;
      const { privateKeyCoder } = coders(detached);
      const f = new Int8Array(n);
      const g = new Int8Array(n);
      const F = new Int8Array(n);
      g[0] = 1;
      const bad = privateKeyCoder.encode([f, g, F]);
      throws(() => detached.getPublicKey(bad), /invalid secretKey/);
      throws(() => detached.sign(msg, bad), /invalid secretKey/);
      throws(() => detached.attached.seal(msg, bad), /invalid secretKey/);
    }
  });
  should('falcon-sign interop', () => {
    const MSG = hexToBytes('68656c6c6f00');
    const SIG = hexToBytes(
      ''
    );
    const PK = hexToBytes(
      ''
    );
    const SK = hexToBytes(
      ''
    );
    // old broken stuff ([2B len][nonce][0x20+logn][sig]) <-> Falcon round3 detached format ([0x30+logn][nonce][sig])
    const BrokenSig = {
      encode(sig) {
        const sigLen = (sig[0] << 8) | sig[1];
        const sigStart = 2 + 40;
        const sigEnd = sigStart + sigLen;
        if (sig.length < sigEnd) throw new Error('Invalid sig: too short');
        const nonce = sig.subarray(2, sigStart);
        const sigBytes = sig.subarray(sigStart, sigEnd);
        const logn = sigBytes[0] - 0x20;
        if (logn < 0 || logn > 15) throw new Error('Invalid logn in header');
        return concatBytes(new Uint8Array([0x30 + logn]), nonce, sigBytes.subarray(1));
      },
      decode(detached) {
        if (detached.length < 1 + 40) throw new Error('Detached too short');
        const header = detached[0];
        if (header < 0x30 || header > 0x3f) throw new Error('Invalid detached header');
        const logn = header - 0x30;
        const kernelHeader = 0x20 + logn;
        const nonce = detached.subarray(1, 41);
        const sigBytes = detached.subarray(41);
        const sigLen = sigBytes.length + 1;
        return concatBytes(
          new Uint8Array([(sigLen >> 8) & 0xff, sigLen & 0xff]),
          nonce,
          new Uint8Array([kernelHeader]),
          sigBytes
        );
      },
    };
    deepStrictEqual(BrokenSig.decode(BrokenSig.encode(SIG)), SIG);
    deepStrictEqual(falcon.falcon512.verify(BrokenSig.encode(SIG), MSG, PK), true);
  });
});
should.opts.FAST = false;
should.runWhen(import.meta.url);
